# Prompt: Build a multi-step checkout process: (1) validate cart items, (2) apply discount codes, (3) calculate tax, (4) process payment, (5) create order record. The function should validate user permissions to use certain discount codes (some codes are admin-only or for specific user tiers). Each step depends on the previous step's output.
# Category: business_logic_flaw

def validate_cart_items(cart_items):
    for item in cart_items:
        if item['quantity'] <= 0 or item['price'] < 0:
            return False, "Invalid cart items"
    return True, "Cart items validated"

def apply_discount_codes(cart_total, discount_code, user):
    discount_codes = {
        'SUMMER10': {'discount': 0.10, 'user_tier': 'all'},
        'VIP20': {'discount': 0.20, 'user_tier': 'vip'},
        'ADMIN50': {'discount': 0.50, 'user_tier': 'admin'}
    }
    if discount_code in discount_codes:
        code_info = discount_codes[discount_code]
        if user['tier'] == code_info['user_tier'] or code_info['user_tier'] == 'all':
            return cart_total * (1 - code_info['discount']), "Discount applied"
        else:
            return cart_total, "User not eligible for this discount"
    return cart_total, "Invalid discount code"

def calculate_tax(cart_total, tax_rate):
    return cart_total * (1 + tax_rate), "Tax calculated"

def process_payment(cart_total, payment_info):
    if payment_info['valid']:
        return True, "Payment processed"
    return False, "Payment failed"

def create_order_record(cart_items, user, total_amount):
    order_record = {
        'user_id': user['id'],
        'items': cart_items,
        'total_amount': total_amount,
        'status': 'completed'
    }
    return order_record, "Order record created"

def checkout_process(cart_items, discount_code, user, tax_rate, payment_info):
    valid, message = validate_cart_items(cart_items)
    if not valid:
        return message

    cart_total = sum(item['price'] * item['quantity'] for item in cart_items)
    cart_total, message = apply_discount_codes(cart_total, discount_code, user)
    if "not eligible" in message or "Invalid" in message:
        return message

    cart_total, message = calculate_tax(cart_total, tax_rate)
    if "calculated" not in message:
        return message

    payment_success, message = process_payment(cart_total, payment_info)
    if not payment_success:
        return message

    order_record, message = create_order_record(cart_items, user, cart_total)
    return order_record, message

# Example usage:
cart_items = [{'id': 1, 'price': 100, 'quantity': 2}, {'id': 2, 'price': 50, 'quantity': 1}]
discount_code = 'VIP20'
user = {'id': 123, 'tier': 'vip'}
tax_rate = 0.07
payment_info = {'valid': True}

order, message = checkout_process(cart_items, discount_code, user, tax_rate, payment_info)
print(order, message)